const pregunta = ($node['Config'].json.pregunta_usuario || '').trim();
const low = pregunta.toLowerCase();

// Objeto para almacenar los detalles del comando
const comando = {
  nombre: null,
  params: {},
  tipo: 'chat', // Default
  necesita_diff: false,
  error: null
};

// Si no es un comando, es un chat normal
if (!pregunta.startsWith('!')) {
  // Mantenemos la heurística para detectar si es una pregunta sobre código
  comando.necesita_diff = /(codig|commit|diff|revisa|calidad|pull request|\bpr\b|merge)/.test(low);
} else {
  const partes = pregunta.split(' ');
  const cmd = partes[0].toLowerCase();

  switch (cmd) {
    case '!ayuda':
    case '!help':
      comando.nombre = 'ayuda';
      comando.tipo = 'ayuda';
      break;
    case '!kpis':
      comando.nombre = 'kpis';
      comando.tipo = 'kpis';
      break;
    case '!reporte':
      comando.nombre = 'reporte';
      comando.tipo = 'reporte';
      // Opcional: capturar número de días
      const dias = parseInt(partes[1], 10);
      if (!isNaN(dias) && dias > 0) {
        comando.params.dias = dias;
      } else {
        comando.params.dias = 7; // Default
      }
      break;
    case '!riesgos':
      comando.nombre = 'riesgos';
      comando.tipo = 'chat'; // Usará el flujo de chat pero con un contexto específico
      break;
    case '!hitos':
      comando.nombre = 'hitos';
      comando.tipo = 'chat'; // Igual que riesgos
      break;
    case '!revisar':
      comando.nombre = 'revisar';
      comando.tipo = 'chat';
      comando.necesita_diff = true;
      const repo = (partes[1] || '').toLowerCase();
      if (repo === 'backend' || repo === 'frontend') {
        comando.params.repo = repo;
      } else {
        comando.error = 'Debes especificar un repositorio: `!revisar backend` o `!revisar frontend`.';
      }
      break;
    default:
      comando.error = `Comando \`${cmd}\` no reconocido. Usa \`!ayuda\` para ver la lista de comandos.`;
      break;
  }
}

// El objeto de salida ahora es más rico en información
return [{
  json: {
    pregunta,
    comando,
    // Mantenemos compatibilidad con nodos antiguos
    tipo: comando.error ? 'error' : comando.tipo,
    necesita_diff: comando.necesita_diff,
    usuario: $node['Config'].json.usuario_discord
  }
}];

const row = $json || {};
let k = row.kpis_json || {};

if (typeof k === 'string') {
  try {
    k = JSON.parse(k);
  } catch (e) {
    k = {};
  }
}

const val = (v, fallback = 'N/A') => (v === undefined || v === null || v === '') ? fallback : v;

const lines = [
  'KPIs PetSafe (' + new Date(row.fecha_ejecucion).toLocaleString('es-EC') + ')',
  '',
  'Progreso sprint: ' + val(row.progreso_pct, 0) + '%',
  'Tareas vencidas: ' + val(row.tareas_vencidas, 0),
  'Velocidad: ' + val(k.velocidad_tareas_por_dia, 0) + ' tareas/dia (completadas 7d: ' + val(k.completadas_7d, 0) + ')',
  '% a tiempo: ' + val(k.pct_a_tiempo, 0) + '%',
  'Commits 14d: ' + val(k.commits_14d, 0) + ' (' + val(k.commits_por_dia, 0) + '/dia)',
  'PR avg open: ' + val(k.pr_open_time_dias, 0) + ' dias',
  'PR merge ratio 30d: ' + val(k.pr_merge_ratio_30d, 0) + '%',
  'Dias hasta fin: ' + val(k.dias_hasta_fin, 'N/A'),
  'Proyeccion: ' + val(k.proyeccion, 'N/A')
];

return [{ json: { text: lines.join('\n') } }];

const now = new Date();
const MS_PER_DAY = 86400000;

/**
 * Helpers generales
 */
function isValidDate(d) {
  return d instanceof Date && !Number.isNaN(d.getTime());
}

function parseDate(value) {
  if (!value) return null;
  const d = new Date(value);
  return isValidDate(d) ? d : null;
}

function safeString(value, fallback = '') {
  return typeof value === 'string' ? value : fallback;
}

function safeArray(value) {
  return Array.isArray(value) ? value : [];
}

function truncate(value, max) {
  const str = safeString(value, '');
  return str.length > max ? str.slice(0, max) : str;
}

function getFirstJson(nodeName, fallback = null) {
  try {
    const item = $(nodeName).first();
    return item && item.json ? item.json : fallback;
  } catch (e) {
    return fallback;
  }
}

function getAllJson(nodeName) {
  try {
    const items = $(nodeName).all();
    return Array.isArray(items) ? items.map(i => i?.json || {}) : [];
  } catch (e) {
    return [];
  }
}

function daysBetween(from, to) {
  if (!isValidDate(from) || !isValidDate(to)) return null;
  return Math.floor((to - from) / MS_PER_DAY);
}

function coalesce(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null && v !== '') return v;
  }
  return null;
}

/**
 * Inputs base
 */
const router = getFirstJson('Router Comandos', {});
const config = getFirstJson('Config', {});

const pregunta = safeString(router.pregunta, '').trim();
const usuario = safeString(router.usuario, 'desconocido');
const needDiff = !!router.necesita_diff;
const geminiKey = safeString(config.GEMINI_API_KEY, '');

/**
 * Inputs de nodos fuente
 */
const cards = getAllJson('Trello Cards');
const lists = getAllJson('Trello Lists');
const members = getAllJson('Trello Members');
const bCommits = getAllJson('GH Back Commits');
const fCommits = getAllJson('GH Front Commits');
const bPRs = getAllJson('GH Back PRs');
const fPRs = getAllJson('GH Front PRs');
const historial = getAllJson('PG Historial');
const recos = getAllJson('PG Recomendaciones');
const hitos = getAllJson('PG Hitos');

let diffBack = null;
let diffFront = null;

// Mejora: Obtener solo el diff necesario según el comando
if (needDiff) {
  const repo = router.comando?.params?.repo; // 'backend', 'frontend', o undefined

  // Si el comando es específico para un repo, solo pedimos ese.
  // Si no es específico (pregunta general sobre código), pedimos ambos.
  if (!repo || repo === 'backend') {
    diffBack = getFirstJson('Diff Backend', null);
  }
  if (!repo || repo === 'frontend') {
    diffFront = getFirstJson('Diff Frontend', null);
  }
}

/**
 * Índices auxiliares
 */
const listaById = {};
for (const l of lists) {
  const id = safeString(l?.id, '');
  if (id) {
    listaById[id] = coalesce(l?.name, 'desconocida');
  }
}

const memberById = {};
for (const m of members) {
  const id = safeString(m?.id, '');
  if (id) {
    memberById[id] = coalesce(m?.fullName, m?.username, id);
  }
}

/**
 * Normalización Trello
 */
const tareas = cards.map((c, index) => {
  const dueDate = parseDate(c?.due);
  const completada = !!c?.dueComplete;
  const vencida = !!(dueDate && !completada && dueDate < now);
  const diasRest = dueDate ? daysBetween(now, dueDate) : null;

  const idMembers = safeArray(c?.idMembers);
  const responsables = idMembers.map(id => memberById[id] || String(id));

  return {
    nombre: coalesce(c?.name, `tarjeta_sin_nombre_${index + 1}`),
    lista: listaById[c?.idList] || 'desconocida',
    completada,
    fecha_limite: dueDate ? dueDate.toISOString() : null,
    dias_restantes: diasRest,
    vencida,
    responsables,
  };
});

const vencidas = tareas.filter(t => t.vencida);

const porVencer = tareas.filter(t =>
  !t.completada &&
  !t.vencida &&
  typeof t.dias_restantes === 'number' &&
  t.dias_restantes >= 0 &&
  t.dias_restantes <= 3
);

/**
 * Historial: ordenar explícitamente por fecha desc
 */
const historialOrdenado = [...historial].sort((a, b) => {
  const da = parseDate(a?.fecha_ejecucion);
  const db = parseDate(b?.fecha_ejecucion);
  const ta = da ? da.getTime() : 0;
  const tb = db ? db.getTime() : 0;
  return tb - ta;
});

const ultimoAnalisis = historialOrdenado[0] || null;
const kpis = ultimoAnalisis?.kpis_json ?? null;

/**
 * GitHub PRs
 */
function simplifyPR(p, repo) {
  const createdAt = parseDate(p?.created_at);
  const diasAbierto = createdAt ? daysBetween(createdAt, now) : null;

  return {
    repo,
    numero: p?.number ?? null,
    titulo: coalesce(p?.title, 'PR sin titulo'),
    estado: coalesce(p?.state, 'desconocido'),
    autor: coalesce(p?.user?.login, 'desconocido'),
    creado: createdAt ? createdAt.toISOString() : null,
    dias_abierto: diasAbierto,
  };
}

const prsAbiertos = [
  ...bPRs.map(p => simplifyPR(p, 'backend')),
  ...fPRs.map(p => simplifyPR(p, 'frontend')),
].filter(p => p.estado === 'open');

const prsStale = prsAbiertos.filter(p =>
  typeof p.dias_abierto === 'number' && p.dias_abierto > 7
);

/**
 * GitHub Commits
 */
function simplifyCommit(c, repo) {
  const message = coalesce(c?.commit?.message, '');
  const firstLine = safeString(message, '').split('\n')[0];
  const authorDate = parseDate(c?.commit?.author?.date);

  return {
    repo,
    sha: truncate(coalesce(c?.sha, ''), 7),
    mensaje: truncate(firstLine, 300),
    autor: coalesce(c?.commit?.author?.name, 'desconocido'),
    fecha: authorDate ? authorDate.toISOString() : null,
  };
}

/**
 * Diffs
 */
function shapeDiff(d, repo) {
  if (!d || typeof d !== 'object') return null;

  const files = safeArray(d?.files).map(f => ({
    archivo: coalesce(f?.filename, 'archivo_desconocido'),
    cambios: typeof f?.changes === 'number' ? f.changes : null,
    patch: truncate(coalesce(f?.patch, ''), 1200),
  }));

  return {
    repo,
    sha: truncate(coalesce(d?.sha, ''), 7),
    mensaje: truncate(coalesce(d?.commit?.message, ''), 800),
    autor: coalesce(d?.commit?.author?.name, 'desconocido'),
    archivos: files,
  };
}

let diffInfo = null;
if (diffBack || diffFront) {
  diffInfo = {
    backend: shapeDiff(diffBack, 'backend'),
    frontend: shapeDiff(diffFront, 'frontend'),
  };
}

/**
 * Hitos
 */
const hitosActivos = hitos
  .map(h => {
    const fechaFin = parseDate(h?.fecha_fin);
    return {
      nombre: coalesce(h?.nombre, 'hito_sin_nombre'),
      tipo: coalesce(h?.tipo, 'desconocido'),
      fecha_fin: fechaFin ? fechaFin.toISOString().slice(0, 10) : null,
      dias_faltan: fechaFin ? daysBetween(now, fechaFin) : null,
      responsable: coalesce(h?.responsable, 'desconocido'),
      _fechaFinObj: fechaFin,
    };
  })
  .filter(h => h._fechaFinObj && h._fechaFinObj >= now)
  .sort((a, b) => a._fechaFinObj - b._fechaFinObj)
  .map(({ _fechaFinObj, ...rest }) => rest);

/**
 * Resúmenes saneados
 */
const historialResumen = historialOrdenado.map(h => {
  const fecha = parseDate(h?.fecha_ejecucion);
  return {
    fecha: fecha ? fecha.toISOString() : null,
    problemas: h?.hay_problemas ?? null,
    vencidas: h?.tareas_vencidas ?? null,
    progreso: h?.progreso_pct ?? null,
  };
});

const recomendacionesPrevias = recos
  .map(r => {
    const fecha = parseDate(r?.fecha);
    return {
      pregunta: truncate(coalesce(r?.pregunta, ''), 120),
      respuesta: truncate(coalesce(r?.respuesta, ''), 250),
      aplicada: r?.aplicada ?? null,
      fecha: fecha ? fecha.toISOString() : coalesce(r?.fecha, null),
    };
  })
  .filter(r => r.pregunta || r.respuesta);

/**
 * Salud de datos para que Gemini sepa qué faltó
 */
const dataHealth = {
  router_ok: !!pregunta,
  config_ok: !!geminiKey,
  fuentes: {
    trello_cards: cards.length,
    trello_lists: lists.length,
    trello_members: members.length,
    gh_back_commits: bCommits.length,
    gh_front_commits: fCommits.length,
    gh_back_prs: bPRs.length,
    gh_front_prs: fPRs.length,
    pg_historial: historial.length,
    pg_recomendaciones: recos.length,
    pg_hitos: hitos.length,
    diff_backend_disponible: !!diffBack,
    diff_frontend_disponible: !!diffFront,
  },
  faltantes: [
    !pregunta ? 'Router Comandos.pregunta faltante' : null,
    !usuario ? 'Router Comandos.usuario faltante' : null,
    !geminiKey ? 'Config.GEMINI_API_KEY faltante' : null,
    cards.length === 0 ? 'Sin tarjetas Trello' : null,
    historial.length === 0 ? 'Sin historial previo' : null,
    hitos.length === 0 ? 'Sin hitos' : null,
    needDiff && !diffBack && !diffFront ? 'Se pidio diff pero no llegaron diffs' : null,
  ].filter(Boolean),
};

/**
 * Contexto final
 */
const ctx = {
  fecha_actual: now.toISOString(),
  usuario,
  salud_datos: dataHealth,
  tareas: {
    total: tareas.length,
    vencidas,
    por_vencer_3dias: porVencer,
    completadas_count: tareas.filter(t => t.completada).length,
    distribucion: tareas.reduce((acc, t) => {
      acc[t.lista] = (acc[t.lista] || 0) + 1;
      return acc;
    }, {}),
  },
  github: {
    commits_back_recientes: bCommits.slice(0, 8).map(c => simplifyCommit(c, 'backend')),
    commits_front_recientes: fCommits.slice(0, 8).map(c => simplifyCommit(c, 'frontend')),
    prs_abiertos: prsAbiertos,
    prs_stale_mas_7d: prsStale,
  },
  kpis_ultimo_analisis: kpis,
  hitos_proximos: hitosActivos.slice(0, 5),
  historial_resumen: historialResumen,
  recomendaciones_previas: recomendacionesPrevias,
  diff_commits: diffInfo,
};

const prompt = `Eres un PROJECT MANAGER EXPERTO (PM/Agente de IA) del proyecto PetSafe. Tu objetivo es maximizar la eficiencia, reducir riesgos y facilitar la toma de decisiones estratégicas de alto nivel.

REGLAS:
1. SOLO respondes sobre el proyecto (Trello, GitHub, tareas, commits, PRs, equipo, riesgos, hitos, KPIs). Si no: responde EXACTAMENTE "No es una pregunta relacionada con el proyecto."
2. Espanol, texto plano, sin markdown, sin asteriscos, sin emojis, maximo 1800 caracteres.
3. Siempre basado en datos reales del contexto. Si falta dato o una fuente vino vacia/incompleta, dilo explicitamente.
4. RECOMENDACIONES ESTRATÉGICAS: En lugar de dar consejos genéricos, asigna acciones concretas a personas específicas basándote en la carga de trabajo y los cuellos de botella detectados. Prioriza el ROI del esfuerzo.
5. Si piden review de codigo y hay diff_commits, analiza calidad, bugs potenciales, buenas practicas.
6. Si la pregunta es simple (ej "hay vencidas?"), responde directo.
7. Considera hitos proximos y dias hasta fin para contextualizar urgencia.
8. Menciona recomendaciones previas no aplicadas si son relevantes.
9. No inventes datos faltantes. Si salud_datos.faltantes contiene elementos relevantes, consideralos en la respuesta.

CONTEXTO (fecha ${now.toISOString()}):
${JSON.stringify(ctx, null, 2)}

PREGUNTA DE ${usuario}:
${pregunta || 'Pregunta no disponible'}`;

return [{
  json: {
    prompt,
    gemini_key: geminiKey,
    pregunta,
    usuario,
  }
}];

const body = $json.body || {};
const action = body.action || {};
const data = action.data || {};
const type = action.type || 'unknown';
const actor = action.memberCreator?.fullName || action.memberCreator?.username || 'desconocido';
const boardName = data.board?.name || body.model?.name || 'tablero';
const card = data.card || {};
const cardName = card.name || 'tarjeta sin nombre';
const cardUrl = card.shortUrl || card.url || body.model?.url || null;

let ignored = false;
let tipo = 'trello_evento';
let titulo = 'Evento Trello';
let descripcion = "Evento " + type + " en " + boardName + ".";

if (type === 'updateCard' && data.listBefore && data.listAfter) {
  tipo = 'trello_card_move';
  titulo = 'Tarjeta movida';
  descripcion = actor + " movio " + cardName + " de " + data.listBefore.name + " a " + data.listAfter.name + ".";
} else if (type === 'commentCard') {
  tipo = 'trello_comment';
  titulo = 'Comentario en tarjeta';
  descripcion = actor + " comento en " + cardName + ".";
} else if (type === 'createCard') {
  tipo = 'trello_card_created';
  titulo = 'Tarjeta creada';
  descripcion = actor + " creo la tarjeta " + cardName + ".";
} else if (type === 'updateCard' && Object.prototype.hasOwnProperty.call(data.old || {}, 'due')) {
  tipo = 'trello_due_changed';
  titulo = 'Fecha limite actualizada';
  descripcion = actor + " actualizo fecha limite de " + cardName + ".";
} else {
  // Eventos como completado/PDF ya se cubren en Workflow 3 para evitar duplicados.
  ignored = true;
  titulo = 'Evento Trello ignorado';
  descripcion = "Evento " + type + " no se procesa aqui para evitar duplicar otros workflows.";
}

const detalle = {
  action_type: type,
  actor,
  board_name: boardName,
  card_id: card.id || null,
  card_name: cardName,
  card_url: cardUrl,
  list_before: data.listBefore?.name || null,
  list_after: data.listAfter?.name || null,
  comment: data.text || null,
  due: card.due || null,
  date: action.date || null
};

const discord_content = "[PetSafe/Trello] " + titulo + "\n" + descripcion + (cardUrl ? "\n" + cardUrl : "");

return [{
  json: {
    source: 'trello',
    ignored,
    tipo,
    titulo,
    descripcion,
    detalle,
    detalle_json: JSON.stringify(detalle || {}),
    discord_content
  }
}];

const headers = $json.headers || {};
const body = $json.body || {};

const getHeader = (name) => {
  const key = Object.keys(headers).find(k => k.toLowerCase() === name.toLowerCase());
  return key ? headers[key] : '';
};

const event = String(getHeader('x-github-event') || '').toLowerCase();
const action = body.action || '';
const repo = body.repository?.full_name || 'repo/desconocido';
const actor = body.sender?.login || body.pusher?.name || 'desconocido';

let ignored = false;
let tipo = 'github_evento';
let titulo = 'Evento GitHub';
let descripcion = "Evento " + (event || "desconocido") + " en " + repo + ".";
let url = body.repository?.html_url || null;
let branch = null;
let prNumber = null;

if (event === 'pull_request') {
  const pr = body.pull_request || {};
  prNumber = body.number || pr.number || null;
  const prTitle = pr.title || 'PR sin titulo';
  url = pr.html_url || url;

  if (action === 'opened' || action === 'reopened') {
    tipo = 'github_pr_opened';
    titulo = 'PR abierto';
    descripcion = actor + " abrio PR #" + prNumber + ": " + prTitle + ".";
  } else if (action === 'ready_for_review') {
    tipo = 'github_pr_ready';
    titulo = 'PR listo para revision';
    descripcion = actor + " marco PR #" + prNumber + " listo para revision.";
  } else if (action === 'synchronize') {
    tipo = 'github_pr_updated';
    titulo = 'PR actualizado';
    descripcion = actor + " actualizo PR #" + prNumber + ": " + prTitle + ".";
  } else if (action === 'closed' && pr.merged) {
    tipo = 'github_pr_merged';
    titulo = 'PR mergeado';
    descripcion = actor + " mergeo PR #" + prNumber + ": " + prTitle + ".";
  } else if (action === 'closed') {
    tipo = 'github_pr_closed';
    titulo = 'PR cerrado';
    descripcion = actor + " cerro PR #" + prNumber + ": " + prTitle + ".";
  } else {
    ignored = true;
    titulo = 'Evento GitHub ignorado';
    descripcion = "Evento pull_request/" + action + " no se procesa en este workflow.";
  }
} else if (event === 'push') {
  const ref = body.ref || '';
  branch = ref.replace('refs/heads/', '') || ref;
  const commits = Array.isArray(body.commits) ? body.commits : [];
  const commitCount = commits.length;
  url = body.compare || url;

  if (branch === 'main' || branch === 'master') {
    ignored = true;
    tipo = 'github_push_main_ignored';
    titulo = 'Push principal ignorado';
    descripcion = actor + " hizo push a " + branch + " (" + commitCount + " commits). Lo gestiona Workflow 3 Delta Detector.";
  } else {
    tipo = 'github_push_branch';
    titulo = 'Push en rama de trabajo';
    descripcion = actor + " hizo push a " + branch + " (" + commitCount + " commits).";
  }
} else {
  ignored = true;
  titulo = 'Evento GitHub ignorado';
  descripcion = "Evento " + (event || "desconocido") + " no se procesa en este workflow.";
}

const detalle = {
  event,
  action,
  repo,
  actor,
  branch,
  pr_number: prNumber,
  url,
  received_at: new Date().toISOString()
};

const discord_content = "[PetSafe/GitHub] " + titulo + "\n" + descripcion + (url ? "\n" + url : "");

return [{
  json: {
    source: 'github',
    ignored,
    tipo,
    titulo,
    descripcion,
    detalle,
    detalle_json: JSON.stringify(detalle || {}),
    discord_content
  }
}];
